mapper.select:
select *
from store_member
where store_id = #{storeId}
  and member_bno = #{memberBno}
  and chk = 1
limit 1

mapper.update:
update store_member
set chk = 1
where store_member_id = #{storeMemberId}
  and store_id = #{storeId}
  and chk = 0

mapper.delete:
delete from store_member
where store_member_id = #{storeMemberId}
  and store_id = #{storeId}
  and chk = 0

mapper.update:
update store_member
set employment = #{employment},
	health = #{health},
	rate = #{rate}
where store_id = #{storeId}
  and member_bno = #{memberBno}
  and position = '직원'

mapper.select:
select count(*)
from schedule sc
join store_member sm on sm.store_member_id = sc.store_employee_bno
where sm.store_id = #{storeId}
  and sc.store_employee_bno = #{storeEmployeeBno}
  and sc.work_date = #{workDate}
  and sc.start_time < #{endTime}
  and sc.end_time > #{startTime}

select count(*)
from schedule sc
join store_member sm on sm.store_member_id = sc.store_employee_bno
where sm.store_id = #{storeId}
  and sc.bno != #{scheduleId}
  and sc.store_employee_bno = #{storeEmployeeBno}
  and sc.work_date = #{workDate}
  and sc.start_time < #{endTime}
  and sc.end_time > #{startTime}

mapper.delete:
delete sc
from schedule sc
join store_member sm on sm.store_member_id = sc.store_employee_bno
where sc.bno = #{scheduleId}
  and sm.store_id = #{storeId}
  and sm.position = '직원'

mapper.update:
update schedule_part sp
join store_member owner on owner.store_member_id = sp.store_bno
set sp.part_name = #{partName},
	sp.start_time = #{startTime},
	sp.end_time = #{endTime},
	sp.color_code = #{colorCode},
	sp.sort_order = #{sortOrder}
where owner.store_id = #{storeId}
  and owner.position = '사장'
  and sp.bno = #{partBno}

update schedule sc
join store_member sm on sm.store_member_id = sc.store_employee_bno
set sc.part_bno = null
where sm.store_id = #{storeId}
  and sc.part_bno = #{partBno}

mapper.delete:
delete sp
from schedule_part sp
join store_member owner on owner.store_member_id = sp.store_bno
where owner.store_id = #{storeId}
  and owner.position = '사장'
  and sp.bno = #{partBno}
